// One-shot: inject locally-exported cookies into a Browserbase Context.
// Connects via Playwright CDP to a session attached to the target Context with
// persist:true, addCookies(), navigates to verify auth, then closes — Browserbase
// syncs cookies back to the Context on session end.
//
// Env required: BROWSERBASE_API_KEY, BROWSERBASE_PROJECT_ID, BROWSERBASE_XCOM_CONTEXT_ID
// Reads cookies from /tmp/xcom-cookies.json (Cookie-Editor JSON format).

import fs from "node:fs";
import { chromium } from "playwright-core";

const API_KEY = process.env.BROWSERBASE_API_KEY;
const PROJECT_ID = process.env.BROWSERBASE_PROJECT_ID;
const CONTEXT_ID = process.env.BROWSERBASE_XCOM_CONTEXT_ID;
const COOKIE_FILE = "/tmp/xcom-cookies.json";

if (!API_KEY || !PROJECT_ID || !CONTEXT_ID) {
  console.error("Missing env: BROWSERBASE_API_KEY, BROWSERBASE_PROJECT_ID, BROWSERBASE_XCOM_CONTEXT_ID");
  process.exit(1);
}

// 1. Load + translate cookies (Cookie-Editor JSON → Playwright shape).
const raw = JSON.parse(fs.readFileSync(COOKIE_FILE, "utf8"));
const sameSiteMap = { no_restriction: "None", lax: "Lax", strict: "Strict" };
const cookies = raw.map((c) => {
  const out = {
    name: c.name,
    value: c.value,
    domain: c.domain,
    path: c.path || "/",
    httpOnly: !!c.httpOnly,
    secure: !!c.secure,
  };
  if (typeof c.expirationDate === "number") out.expires = Math.floor(c.expirationDate);
  const ss = c.sameSite ? sameSiteMap[c.sameSite] : null;
  if (ss) out.sameSite = ss;
  return out;
});
console.log(`Loaded ${cookies.length} cookies for x.com`);

// 2. Create a session attached to the target Context (persist:true).
console.log(`Creating session for context ${CONTEXT_ID}...`);
const sessionResp = await fetch("https://api.browserbase.com/v1/sessions", {
  method: "POST",
  headers: { "X-BB-API-Key": API_KEY, "Content-Type": "application/json" },
  body: JSON.stringify({
    projectId: PROJECT_ID,
    browserSettings: { context: { id: CONTEXT_ID, persist: true } },
  }),
});
if (!sessionResp.ok) {
  console.error(`Session create failed: ${sessionResp.status}`, await sessionResp.text());
  process.exit(1);
}
const session = await sessionResp.json();
console.log(`Session ${session.id} running in ${session.region}`);

// 3. Connect via Playwright CDP, inject cookies, verify, close.
let browser;
try {
  browser = await chromium.connectOverCDP(session.connectUrl);
  const ctx = browser.contexts()[0];
  await ctx.addCookies(cookies);
  console.log("Cookies added");

  const page = ctx.pages()[0] ?? (await ctx.newPage());
  await page.goto("https://x.com/home", { waitUntil: "domcontentloaded", timeout: 30000 });
  await page.waitForTimeout(3000);
  const url = page.url();
  const title = await page.title();
  console.log(`Landed on: ${url}`);
  console.log(`Page title: ${title}`);

  // Heuristic: logged-out lands on /login or /i/flow/login. Logged-in stays on /home.
  if (url.includes("/login") || url.includes("/i/flow/login")) {
    console.error("AUTH FAILED — redirected to login. Cookies may be expired or incomplete.");
    process.exit(2);
  }
  console.log("AUTH OK — Context now holds x.com login state.");
} finally {
  if (browser) await browser.close();
  // Tell Browserbase to end the session — triggers cookie writeback to Context.
  await fetch(`https://api.browserbase.com/v1/sessions/${session.id}`, {
    method: "POST",
    headers: { "X-BB-API-Key": API_KEY, "Content-Type": "application/json" },
    body: JSON.stringify({ projectId: PROJECT_ID, status: "REQUEST_RELEASE" }),
  });
  console.log("Session released. Wait ~5s for Context sync.");
}

